import { Icons } from '@beeline/design-tokens/js/iconfont/icons';

import type { StepOrderMapType } from './step.types';

type PickedIconState = Pick<StepOrderMapType, 'success' | 'error' | 'disabled'>;
type PickedOrderState = Pick<StepOrderMapType, 'active' | 'visited' | 'non-visited'>;

export type Icon = keyof PickedIconState;
export type Order = keyof PickedOrderState;

export const ICON_STATE_MAP: Record<Icon, boolean> = {
	success: true,
	error: true,
	disabled: true,
};

export const ORDER_STATE_MAP: Record<Order, boolean> = {
	active: true,
	visited: true,
	'non-visited': true,
};

export const STEP_ICON_MAP = {
	success: Icons.CheckCircled,
	error: Icons.InfoCircled,
	disabled: Icons.Lock,
};
